insert into public.routine_templates (title, slug, goal, experience, days_per_week, short_description, duration_weeks, estimated_session_minutes, level_label, focus_areas, routine_data, is_active) values
  ('Full Body Base para Masa (3 días)','masa-principiante-fullbody-3d','ganar_masa_muscular','principiante',3,'Rutina inicial con ejercicios compuestos para construir masa muscular y técnica.',8,60,'Principiante',ARRAY['hipertrofia inicial','técnica de fuerza','consistencia semanal'],'{"dias":[{"dia":"dia_1","nombre_dia":"Día 1 · Full Body A","enfoque":"Fuerza general de cuerpo completo","musculo":"Fuerza general de cuerpo completo","notas":"Prioriza patrones básicos: sentadilla, empuje, tracción y bisagra de cadera.","ejercicios":[{"nombre":"Sentadilla goblet o trasera","series":3,"repeticiones":"6-10 rep","descanso":"90-120 s","notas":"Mantén el tronco firme y controla la bajada."},{"nombre":"Press de banca o mancuernas","series":3,"repeticiones":"6-10 rep","descanso":"90 s","notas":"Escápulas activas y recorrido completo sin dolor."},{"nombre":"Remo con mancuerna o polea","series":3,"repeticiones":"8-12 rep","descanso":"75-90 s","notas":"Inicia el tirón con espalda, no con bíceps."},{"nombre":"Peso muerto rumano","series":3,"repeticiones":"8-10 rep","descanso":"90 s","notas":"Bisagra limpia, espalda neutra."},{"nombre":"Plancha frontal","series":3,"repeticiones":"30-45 s","descanso":"45 s","notas":"Respira sin perder alineación."}]},{"dia":"dia_2","nombre_dia":"Día 2 · Full Body B","enfoque":"Torso mixto (volumen moderado)","musculo":"Torso mixto (volumen moderado)","notas":"Incrementa repeticiones antes de subir peso en accesorios.","ejercicios":[{"nombre":"Press inclinado en máquina","series":3,"repeticiones":"10-12 rep","descanso":"75 s","notas":"Controla la excéntrica 2 segundos."},{"nombre":"Remo pecho apoyado","series":3,"repeticiones":"10-12 rep","descanso":"75 s","notas":"Sin balanceo de tronco."},{"nombre":"Fondos asistidos o en banco","series":3,"repeticiones":"8-12 rep","descanso":"75 s","notas":"Rango cómodo para hombro."},{"nombre":"Jalón agarre neutro","series":3,"repeticiones":"10-12 rep","descanso":"75 s","notas":"Lleva codos hacia costados."},{"nombre":"Curl martillo + tríceps cuerda","series":3,"repeticiones":"10-12 rep c/u","descanso":"60 s","notas":"Superserie opcional."}]},{"dia":"dia_3","nombre_dia":"Día 3 · Pierna + Core","enfoque":"Pierna base (cuádriceps, glúteo, femoral)","musculo":"Pierna base (cuádriceps, glúteo, femoral)","notas":"Mantén rango de movimiento cómodo y progresa de forma gradual.","ejercicios":[{"nombre":"Sentadilla trasera o en multipower","series":4,"repeticiones":"6-8 rep","descanso":"120-150 s","notas":"Profundidad según movilidad y control."},{"nombre":"Prensa inclinada","series":3,"repeticiones":"10-12 rep","descanso":"90 s","notas":"Empuja con toda la planta del pie."},{"nombre":"Peso muerto rumano","series":3,"repeticiones":"8-10 rep","descanso":"120 s","notas":"Enfoca en femoral y glúteo."},{"nombre":"Zancadas caminando","series":3,"repeticiones":"10-12 rep por pierna","descanso":"75-90 s","notas":"Paso largo y tronco estable."},{"nombre":"Elevación de gemelos","series":3,"repeticiones":"12-15 rep","descanso":"60 s","notas":"Pausa 1 s arriba y abajo."}]}],"recomendaciones_generales":["Inicia cada sesión con 8-12 minutos de calentamiento dinámico y 1-2 series de aproximación en el primer ejercicio.","Trabaja con técnica estable y deja 1-3 repeticiones en reserva en la mayoría de series.","Cuando completes el rango alto de repeticiones en todas las series, aumenta la carga entre 2% y 5% la semana siguiente.","Incluye 5-10 minutos de vuelta a la calma y respiración nasal al finalizar para facilitar la recuperación."]}'::jsonb,true),
  ('Torso-Pierna Inicial (4 días)','masa-principiante-torso-pierna-4d','ganar_masa_muscular','principiante',4,'División clásica para subir volumen de entrenamiento sin exceso de fatiga.',8,65,'Principiante',ARRAY['torso-pierna','progresión simple','hipertrofia general'],'{"dias":[{"dia":"dia_1","nombre_dia":"Día 1 · Torso Empuje","enfoque":"Torso empuje (pecho, hombro, tríceps)","musculo":"Torso empuje (pecho, hombro, tríceps)","notas":"Busca ejecución controlada y evita ir al fallo en todas las series.","ejercicios":[{"nombre":"Press de banca","series":4,"repeticiones":"6-8 rep","descanso":"120 s","notas":"Pies firmes y trayectoria estable."},{"nombre":"Press inclinado con mancuernas","series":3,"repeticiones":"8-10 rep","descanso":"90 s","notas":"Recorrido amplio y controlado."},{"nombre":"Press militar sentado","series":3,"repeticiones":"8-10 rep","descanso":"90 s","notas":"No hiperextiendas la zona lumbar."},{"nombre":"Elevaciones laterales","series":3,"repeticiones":"12-15 rep","descanso":"60 s","notas":"Sube hasta línea de hombro sin balanceo."},{"nombre":"Extensión de tríceps en cuerda","series":3,"repeticiones":"10-12 rep","descanso":"60-75 s","notas":"Codos fijos junto al torso."}]},{"dia":"dia_2","nombre_dia":"Día 2 · Pierna Base","enfoque":"Pierna base (cuádriceps, glúteo, femoral)","musculo":"Pierna base (cuádriceps, glúteo, femoral)","notas":"Mantén rango de movimiento cómodo y progresa de forma gradual.","ejercicios":[{"nombre":"Sentadilla trasera o en multipower","series":4,"repeticiones":"6-8 rep","descanso":"120-150 s","notas":"Profundidad según movilidad y control."},{"nombre":"Prensa inclinada","series":3,"repeticiones":"10-12 rep","descanso":"90 s","notas":"Empuja con toda la planta del pie."},{"nombre":"Peso muerto rumano","series":3,"repeticiones":"8-10 rep","descanso":"120 s","notas":"Enfoca en femoral y glúteo."},{"nombre":"Zancadas caminando","series":3,"repeticiones":"10-12 rep por pierna","descanso":"75-90 s","notas":"Paso largo y tronco estable."},{"nombre":"Elevación de gemelos","series":3,"repeticiones":"12-15 rep","descanso":"60 s","notas":"Pausa 1 s arriba y abajo."}]},{"dia":"dia_3","nombre_dia":"Día 3 · Torso Tracción","enfoque":"Torso tracción (espalda y bíceps)","musculo":"Torso tracción (espalda y bíceps)","notas":"Controla la fase excéntrica para mejorar estímulo y técnica.","ejercicios":[{"nombre":"Jalón al pecho","series":4,"repeticiones":"8-10 rep","descanso":"90 s","notas":"Lleva la barra al pecho sin balancearte."},{"nombre":"Remo con barra o T-bar","series":4,"repeticiones":"6-10 rep","descanso":"90-120 s","notas":"Mantén columna neutra durante todo el set."},{"nombre":"Remo en polea baja","series":3,"repeticiones":"10-12 rep","descanso":"75 s","notas":"Pausa breve con escápulas juntas."},{"nombre":"Face pull","series":3,"repeticiones":"12-15 rep","descanso":"60 s","notas":"Lleva las manos hacia la cara con codos altos."},{"nombre":"Curl de bíceps con barra Z","series":3,"repeticiones":"10-12 rep","descanso":"60 s","notas":"Evita impulso de cadera."}]},{"dia":"dia_4","nombre_dia":"Día 4 · Pierna Posterior","enfoque":"Pierna posterior y estabilidad","musculo":"Pierna posterior y estabilidad","notas":"Sesión orientada a cadena posterior y prevención de desbalances.","ejercicios":[{"nombre":"Hip thrust","series":4,"repeticiones":"8-10 rep","descanso":"90 s","notas":"Extiende cadera con pausa arriba."},{"nombre":"Peso muerto con barra hexagonal","series":3,"repeticiones":"5-8 rep","descanso":"120 s","notas":"Carga progresiva con técnica sólida."},{"nombre":"Curl femoral en máquina","series":3,"repeticiones":"10-12 rep","descanso":"75 s","notas":"Controla la vuelta del peso."},{"nombre":"Sentadilla búlgara","series":3,"repeticiones":"8-10 rep por pierna","descanso":"90 s","notas":"Rodilla alineada con punta del pie."},{"nombre":"Pallof press","series":3,"repeticiones":"10-12 rep por lado","descanso":"45-60 s","notas":"Resiste rotación del tronco."}]}],"recomendaciones_generales":["Inicia cada sesión con 8-12 minutos de calentamiento dinámico y 1-2 series de aproximación en el primer ejercicio.","Trabaja con técnica estable y deja 1-3 repeticiones en reserva en la mayoría de series.","Cuando completes el rango alto de repeticiones en todas las series, aumenta la carga entre 2% y 5% la semana siguiente.","Incluye 5-10 minutos de vuelta a la calma y respiración nasal al finalizar para facilitar la recuperación."]}'::jsonb,true),
