o":"Cardio base + core","notas":"Mantén intensidad moderada (hablar en frases cortas) y técnica limpia en core.","ejercicios":[{"nombre":"Caminata inclinada o bici","series":1,"repeticiones":"25-35 min zona moderada","descanso":"-","notas":"Ritmo continuo sin picos excesivos."},{"nombre":"Intervalos suaves en remo","series":6,"repeticiones":"1 min rápido / 1 min suave","descanso":"60 s","notas":"Esfuerzo 7/10 en tramo rápido."},{"nombre":"Plancha lateral","series":3,"repeticiones":"30-40 s por lado","descanso":"30-45 s","notas":"Cadera alineada con hombro y tobillo."},{"nombre":"Dead bug","series":3,"repeticiones":"10-12 rep por lado","descanso":"30 s","notas":"Controla respiración y zona lumbar."}]},{"dia":"dia_4","nombre_dia":"Día 4 · Pierna posterior","enfoque":"Pierna posterior y estabilidad","musculo":"Pierna posterior y estabilidad","notas":"Sesión orientada a cadena posterior y prevención de desbalances.","ejercicios":[{"nombre":"Hip thrust","series":4,"repeticiones":"8-10 rep","descanso":"90 s","notas":"Extiende cadera con pausa arriba."},{"nombre":"Peso muerto con barra hexagonal","series":3,"repeticiones":"5-8 rep","descanso":"120 s","notas":"Carga progresiva con técnica sólida."},{"nombre":"Curl femoral en máquina","series":3,"repeticiones":"10-12 rep","descanso":"75 s","notas":"Controla la vuelta del peso."},{"nombre":"Sentadilla búlgara","series":3,"repeticiones":"8-10 rep por pierna","descanso":"90 s","notas":"Rodilla alineada con punta del pie."},{"nombre":"Pallof press","series":3,"repeticiones":"10-12 rep por lado","descanso":"45-60 s","notas":"Resiste rotación del tronco."}]},{"dia":"dia_5","nombre_dia":"Día 5 · Recuperación activa técnica","enfoque":"Técnica, movilidad y recuperación activa","musculo":"Técnica, movilidad y recuperación activa","notas":"Sesión ligera para sostener volumen semanal sin fatiga excesiva.","ejercicios":[{"nombre":"Movilidad dinámica global","series":1,"repeticiones":"10-12 min","descanso":"-","notas":"Hombros, cadera, tobillo y columna torácica."},{"nombre":"Sentadilla goblet ligera","series":3,"repeticiones":"12 rep","descanso":"60 s","notas":"Enfocada a técnica y rango de movimiento."},{"nombre":"Remo con banda","series":3,"repeticiones":"15 rep","descanso":"45 s","notas":"Activa espalda alta."},{"nombre":"Puente de glúteo","series":3,"repeticiones":"12-15 rep","descanso":"45 s","notas":"Pausa de 1 segundo en extensión."},{"nombre":"Respiración diafragmática","series":1,"repeticiones":"4-5 min","descanso":"-","notas":"Baja pulsaciones antes de terminar."}]}],"recomendaciones_generales":["Inicia cada sesión con 8-12 minutos de calentamiento dinámico y 1-2 series de aproximación en el primer ejercicio.","Trabaja con técnica estable y deja 1-3 repeticiones en reserva en la mayoría de series.","Cuando completes el rango alto de repeticiones en todas las series, aumenta la carga entre 2% y 5% la semana siguiente.","Incluye 5-10 minutos de vuelta a la calma y respiración nasal al finalizar para facilitar la recuperación."]}'::jsonb,true),
