  ('Condición Integral (4 días)','condicion-intermedio-integral-4d','mejorar_condicion_general','intermedio',4,'Rutina completa para mejorar rendimiento diario y composición corporal.',8,55,'Intermedio',ARRAY['fuerza general','resistencia','recuperación'],'{"dias":[{"dia":"dia_1","nombre_dia":"Día 1 · Torso empuje","enfoque":"Torso empuje (pecho, hombro, tríceps)","musculo":"Torso empuje (pecho, hombro, tríceps)","notas":"Busca ejecución controlada y evita ir al fallo en todas las series.","ejercicios":[{"nombre":"Press de banca","series":4,"repeticiones":"6-8 rep","descanso":"120 s","notas":"Pies firmes y trayectoria estable."},{"nombre":"Press inclinado con mancuernas","series":3,"repeticiones":"8-10 rep","descanso":"90 s","notas":"Recorrido amplio y controlado."},{"nombre":"Press militar sentado","series":3,"repeticiones":"8-10 rep","descanso":"90 s","notas":"No hiperextiendas la zona lumbar."},{"nombre":"Elevaciones laterales","series":3,"repeticiones":"12-15 rep","descanso":"60 s","notas":"Sube hasta línea de hombro sin balanceo."},{"nombre":"Extensión de tríceps en cuerda","series":3,"repeticiones":"10-12 rep","descanso":"60-75 s","notas":"Codos fijos junto al torso."}]},{"dia":"dia_2","nombre_dia":"Día 2 · Pierna base","enfoque":"Pierna base (cuádriceps, glúteo, femoral)","musculo":"Pierna base (cuádriceps, glúteo, femoral)","notas":"Mantén rango de movimiento cómodo y progresa de forma gradual.","ejercicios":[{"nombre":"Sentadilla trasera o en multipower","series":4,"repeticiones":"6-8 rep","descanso":"120-150 s","notas":"Profundidad según movilidad y control."},{"nombre":"Prensa inclinada","series":3,"repeticiones":"10-12 rep","descanso":"90 s","notas":"Empuja con toda la planta del pie."},{"nombre":"Peso muerto rumano","series":3,"repeticiones":"8-10 rep","descanso":"120 s","notas":"Enfoca en femoral y glúteo."},{"nombre":"Zancadas caminando","series":3,"repeticiones":"10-12 rep por pierna","descanso":"75-90 s","notas":"Paso largo y tronco estable."},{"nom