  ('Condición Global (5 días)','condicion-avanzado-global-5d','mejorar_condicion_general','avanzado',5,'Distribución avanzada para sostener alto nivel de condición física general.',10,65,'Avanzado',ARRAY['fuerza y cardio','capacidad de trabajo','consistencia'],'{"dias":[{"dia":"dia_1","nombre_dia":"Día 1 · Push","enfoque":"Torso empuje (pecho, hombro, tríceps)","musculo":"Torso empuje (pecho, hombro, tríceps)","notas":"Busca ejecución controlada y evita ir al fallo en todas las series.","ejercicios":[{"nombre":"Press de banca","series":4,"repeticiones":"6-8 rep","descanso":"120 s","notas":"Pies firmes y trayectoria estable."},{"nombre":"Press inclinado con mancuernas","series":3,"repeticiones":"8-10 rep","descanso":"90 s","notas":"Recorrido amplio y controlado."},{"nombre":"Press militar sentado","series":3,"repeticiones":"8-10 rep","descanso":"90 s","notas":"No hiperextiendas la zona lumbar."},{"nombre":"Elevaciones laterales","series":3,"repeticiones":"12-15 rep","descanso":"60 s","notas":"Sube hasta línea de hombro sin balanceo."},{"nombre":"Extensión de tríceps en cuerda","series":3,"repeticiones":"10-12 rep","descanso":"60-75 s","notas":"Codos fijos junto al torso."}]},{"dia":"dia_2","nombre_dia":"Día 2 · Pull","enfoque":"Torso tracción (espalda y bíceps)","musculo":"Torso tracción (espalda y bíceps)","notas":"Controla la fase excéntrica para mejorar estímulo y técnica.","ejercicios":[{"nombre":"Jalón al pecho","series":4,"repeticiones":"8-10 rep","descanso":"90 s","notas":"Lleva la barra al pecho sin balancearte."},{"nombre":"Remo con barra o T-bar","series":4,"repeticiones":"6-10 rep","descanso":"90-120 s","notas":"Mantén columna neutra durante todo el set."},{"nombre":"Remo en polea baja","series":3,"repeticiones":"10-12 rep","descanso":"75 s","notas":"Pausa breve con escápulas juntas."},{"nombre":"Face pull","series":3,"repeticiones":"12-15 rep","descanso":"60 s","notas":"Lleva las manos hacia la cara con codos altos."},{"nombre":"Curl de bíceps con barra Z